function solve(nums1) {
    const n = nums1.length;

    /**
     * Helper function to check if a resulting array can be made all odd or all even.
     * @param {number[]} nums1 The original array.
     * @returns {boolean} True if a valid construction exists, false otherwise.
     */
    function checkPossibility(nums1) {
        // Since N is small (<= 100), we can iterate through all 2^N possibilities,
        // but a full 2^N search is too slow.

        // Let's analyze the constraints on parity.
        // For each i, nums2[i] must be either:
        // 1. nums1[i]
        // 2. nums1[i] - nums1[j] (j != i)

        // The target is either all EVEN or all ODD.

        // Case 1: Target is all EVEN (nums2[i] % 2 == 0 for all i)
        let canBeAllEven = true;
        for (let i = 0; i < n; i++) {
            // Option 1: nums1[i] must be even.
            if (nums1[i] % 2 === 0) continue;

            // Option 2: nums1[i] - nums1[j] must be even for some j != i.
            // nums1[i] - nums1[j] is even <=> nums1[i] and nums1[j] have the same parity.
            // Since nums1[i] is odd, we need an odd nums1[j] where j != i.
            let hasOtherOdd = false;
            for (let j = 0; j < n; j++) {
                if (i !== j && nums1[j] % 2 !== 0) {
                    hasOtherOdd = true;
                    break;
                }
            }
            if (!hasOtherOdd) {
                canBeAllEven = false;
                break;
            }
        }

        if (canBeAllEven) return true;

        // Case 2: Target is all ODD (nums2[i] % 2 == 1 for all i)
        let canBeAllOdd = true;
        for (let i = 0; i < n; i++) {
            // Option 1: nums1[i] must be odd.
            if (nums1[i] % 2 !== 0) continue;

            // Option 2: nums1[i] - nums1[j] must be odd for some j != i.
            // nums1[i] - nums1[j] is odd <=> nums1[i] and nums1[j] have different parities.
            // Since nums1[i] is even, we need an odd nums1[j] where j != i.
            let hasOtherOdd = false;
            for (let j = 0; j < n; j++) {
                if (i !== j && nums1[j] % 2 !== 0) {
                    hasOtherOdd = true;
                    break;
                }
            }
            if (!hasOtherOdd) {
                canBeAllOdd = false;
                break;
            }
        }

        // Special check for all even target when all numbers are even (or only one number)
        // If all nums1[i] are even, they can all be chosen as nums1[i], so it's always true for Even target.
        if (nums1.every(x => x % 2 === 0)) {
            return true; // Already handled by canBeAllEven logic, but safe to re-affirm.
        }

        // Special check for all odd target when all numbers are odd
        // If all nums1[i] are odd, they can all be chosen as nums1[i], so it's always true for Odd target.
        if (nums1.every(x => x % 2 !== 0)) {
            return true; // Already handled by canBeAllOdd logic, but safe to re-affirm.
        }


        return canBeAllOdd;
    }

