    // Let P(x) be the parity of x (0 for even, 1 for odd).
    // Target: All P(nums2[i]) = 0 OR All P(nums2[i]) = 1.

    // For each i, nums2[i] can have parity:
    // 1. P(nums1[i])
    // 2. P(nums1[i] - nums1[j]) = P(nums1[i]) XOR P(nums1[j])

    // We must find a set of choices {choice_i} for i=1..N such that all resulting parities are the same.

    const parities = nums1.map(x => x % 2); // 0 for even, 1 for odd
    const hasEven = parities.includes(0);
    const hasOdd = parities.includes(1);

    // If N=1, we just pick nums1[0], so it's always true.
    if (n === 1) return true;


    // --- Test Target: All Even (Target Parity = 0) ---
    let possibleEven = true;
    for (let i = 0; i < n; i++) {
        // Can nums2[i] be made even?
        const pi = parities[i]; // Parity of nums1[i]

        // Option 1: nums2[i] = nums1[i]. Requires pi = 0.
        if (pi === 0) continue;

        // Option 2: nums2[i] = nums1[i] - nums1[j] (j!=i). Requires pi XOR pj = 0, so pj = pi = 1.
        // We need at least one other odd number nums1[j] (j!=i).
        if (pi === 1) {
            let foundOtherOdd = false;
            for (let j = 0; j < n; j++) {
                if (i !== j && parities[j] === 1) {
                    foundOtherOdd = true;
                    break;
                }
            }
            if (!foundOtherOdd) {
                possibleEven = false;
                break;
            }
        }
    }

    if (possibleEven) return true;

    // --- Test Target: All Odd (Target Parity = 1) ---
    let possibleOdd = true;
    for (let i = 0; i < n; i++) {
        // Can nums2[i] be made odd?
        const pi = parities[i]; // Parity of nums1[i]

        // Option 1: nums2[i] = nums1[i]. Requires pi = 1.
        if (pi === 1) continue;

        // Option 2: nums2[i] = nums1[i] - nums1[j] (j!=i). Requires pi XOR pj = 1, so pj = 1 - pi.
        // If pi = 0 (even), we need pj = 1 (odd).
        if (pi === 0) {
            let foundOtherOdd = false;
            for (let j = 0; j < n; j++) {
                if (i !== j && parities[j] === 1) {
                    foundOtherOdd = true;
                    break;
                }
            }
            if (!foundOtherOdd) {
                possibleOdd = false;
                break;
            }
        }
    }

    return possibleOdd;
