    for i in 0..n {
        let pi = parities[i]; // Parity of nums1[i]

        // If pi == 0, we can choose nums2[i] = nums1[i] (Even).
        if pi == 0 {
            continue;
        }

        // If pi == 1 (Odd), we must use subtraction: nums2[i] = nums1[i] - nums1[j] (j!=i).
        // We need pi XOR pj = 0, so pj = pi = 1.
        // We need at least one other odd number nums1[j] where j != i.
        if pi == 1 {
            let mut found_other_odd = false;
            for j in 0..n {
                if i != j && parities[j] == 1 {
                    found_other_odd = true;
